### Next.js Proxy for Rewriting Paths (TS/JS)

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/backend-for-frontend.mdx

This example shows how to use the Next.js `proxy` function to rewrite an incoming request path to a different URL. It checks for a specific `pathname` and then uses `NextResponse.rewrite()` to transparently fetch content from a new destination, such as an external website.

```ts
import { NextResponse } from 'next/server'

export function proxy(request: Request) {
  if (request.nextUrl.pathname === '/proxy-this-path') {
    const rewriteUrl = new URL('https://nextjs.org')
    return NextResponse.rewrite(rewriteUrl)
  }
}
```

```js
import { NextResponse } from 'next/server'

export function proxy(request) {
  if (request.nextUrl.pathname === '/proxy-this-path') {
    const rewriteUrl = new URL('https://nextjs.org')
    return NextResponse.rewrite(rewriteUrl)
  }
}
```

